var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"예언은 틀리지 않는다.","JPN":"予言は絶対に外れない。","ENG":"The prophecy is never wrong.","TWN":"預言不會出錯。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"황금나무가 종말을 속삭인 순간, 그 이야기는 진실이 된다.","JPN":"黄金の木が終末をささやいた瞬間、その話は真実となる。","ENG":"Once the Golden Tree whispers of the apocalypse, it will become true.","TWN":"當黃金樹低語末日的瞬間，傳說便成為事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그 오랜 세월 끝에 낙원을 발견했을 땐, 마침내 그 진실을 거스를 방법을 찾았다고 생각했다.","JPN":"長い月日の果てに楽園を見つけた時、ついに真実覆す方法を見つけたと思った。","ENG":"When I discovered the Promised Land after all these years, I thought I had finally found a way to defy the truth.","TWN":"在漫長歲月的盡頭，當我發現樂園時，我以為終於找到反抗真相的方法。"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만…","JPN":"でも……","ENG":"But...","TWN":"但…"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가 구원을 향해 나아갈수록, 종말도 가까워진다.","JPN":"アタシたちが救援へ向かって進むほど、終末も近づいてくる。","ENG":"as we marched toward salvation, the end drew nearer.","TWN":"我們越是向著救贖前進，末日也越是臨近。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"마왕의 군세가 인류를 뿌리뽑기 위해 손아귀를 뻗쳐온다.","JPN":"魔王の軍勢が人類の根を絶やすために手を伸ばしてくる。","ENG":"The Demon Lord's army extends its reach to prune humanity off this world.","TWN":"魔王的軍隊伸出魔爪，試圖抹掉人類。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그럼에도…","JPN":"しかし、それでも……","ENG":"And yet...","TWN":"但就算如此…"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 나아가는 것을 멈출 수 없다.","JPN":"アタシは進むことをやめられない。","ENG":"I must keep pushing onward.","TWN":"我也不能停止前進。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 악마가 이곳의 존재를 알게 된 이상, 마왕이 움직이겠지.","JPN":"あの悪魔がここの存在に気付いた以上、魔王が動くはずよ。","ENG":"Now that the devil knows of this place, the Demon Lord will make her move.","TWN":"既然那個魔鬼已經知道了這裡的存在，魔王一定會有所行動。"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그전까지 어떻게든… 나 혼자서라도 낙원문을 완성시켜야 해.","JPN":"それまでなんとか……アタシ一人だけでも楽園の門を完成させないといけないわ。","ENG":"Until then... I must complete Avalon's Gate, even if I have to do it by myself.","TWN":"在那之前，無論如何…就算只有我一個人，也要完成這樂園門。"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"아, 오셨네요.","JPN":"あ、来ましたね。","ENG":"Oh, you're back.","TWN":"喔，您來啦。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"언제 오시나 기다리고 있었습니다, 제사장님.","JPN":"待っていましたよ、祭祀長。","ENG":"We were waiting for your return, High Priest.","TWN":"我一直在等您，祭司長。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희들…?","JPN":"アナタたち……？","ENG":"You…?","TWN":"你們…？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"왜 아직도 여기에 있는 거야?","JPN":"どうしてまだここにいるの？","ENG":"Why are you all still here?","TWN":"為什麼還在這裡？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"그야 낙원으로 가는 길을 열기 위해서죠.","JPN":"そりゃ、楽園への道を開くためですよ。","ENG":"To open the path to the Promised Land, of course.","TWN":"當然是為了打開通往樂園的道路。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"낙원문의 연구는 제사장님이 계시지 않으면 완성할 수 없으니까요.","JPN":"楽園の門の研究は祭祀長がいないと完成できないですから。","ENG":"This research cannot be completed without you, High Priest.","TWN":"因為沒有祭司長，樂園門的研究就無法完成。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아직도 날 돕겠다는… 그런 태연한 소릴 하는 거니?","JPN":"まだアタシを手伝うって……そう言いたいの？","ENG":"How can you so calmly say... that you still wish to help me?","TWN":"你們還想要…幫我嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"무슨 일이 일어나든 저희가 해야할 일은 변치 않습니다.","JPN":"何が起ころうと、私たちのやるべきことは同じです。","ENG":"Whatever happens, the work we must do has not changed.","TWN":"無論發生什麼，我們的任務都不會改變。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"제사장님이 수백 년 동안 변함없이, 저희 선조들의 고향을 지켜주신 것처럼요.","JPN":"祭祀長が数百年の間変わらず、祖先の故郷を守ってくれたように。","ENG":"Much like how you have protected the home of our ancestors for centuries.","TWN":"就像祭司長幾百年來不變地守護著我們祖先的故鄉一樣。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희 선조들이 쌓아온 역사를 송두리째 부정하는 존재가 지금 눈앞에 있어.","JPN":"アナタたちの祖先が築いてきた歴史を丸ごと否定する存在が今目の前にいるわ。","ENG":"I stand before you, a being who completely denies the history your ancestors have accumulated.","TWN":"現在你眼前的這個存在，徹底否定了你們祖先積累的歷史。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"악마가 어떤 존재인지… 모르지 않을 텐데?","JPN":"悪魔がどんな存在なのか……知っているでしょう？","ENG":"I am sure... that you know what a devil is.","TWN":"你應該知道魔鬼是什麼樣子的吧…？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"알고 있어요.","JPN":"わかっています。","ENG":"We do.","TWN":"我知道。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"하지만 우리의 역사는 당신과 함께한 역사이기도 합니다.","JPN":"ですが、私たちの歴史はいつもあなたと共にありました。","ENG":"But you are also part of the history we have created.","TWN":"但是我們的歷史也是與您一起的歷史。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"당신이 어떤 존재이건, 지금까지 그루터기를 이끌어왔다는 진실은 변함없어요.","JPN":"あなたがどんな存在であっても、今まで切り株を導いてきたという真実は変わりません。","ENG":"Whoever you are, it does not change the fact that you have led the Stump until now.","TWN":"無論祭司長是什麼樣的存在，至今為止您引領著我們的這一事實不會改變。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"날 돕고도, 후회하지 않을 자신 있어?","JPN":"アタシを手伝って、後悔しないと言い切れるの？","ENG":"Will you not regret helping me?","TWN":"幫助我，你有信心不會後悔嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"낙원문은 저희 길잡이들이 평생을 바쳐 길러온 나무입니다.","JPN":"楽園の門は我々導き手がずっと育ててきた木です。","ENG":"Avalon's Gate is the tree that we, pathfinders, have devoted their lives to nurturing and growing.","TWN":"這個樂園門是我們引路人用一生所培育的樹木。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};